const output = await pipe('https://example.com/image.jpg', 'Describe this image in detail');
// [{ generated_text: '...' }]
```

Only `src/pipelines.js` needs to be modified. No changes to models, tokenizers, processors, or exports infrastructure (`src/transformers.js` already does `export * from './pipelines.js'`).

---

## File to modify

`src/pipelines.js`

---

## Step-by-step changes

### Step 1 — Add import (line 42)

Add `AutoModelForImageTextToText` to the import block from `./models.js`.

**Location:** After `AutoModelForImageFeatureExtraction` (line 42), before `PreTrainedModel` (line 43).

```js
    AutoModelForImageFeatureExtraction,
    AutoModelForImageTextToText,    // <-- ADD THIS
    PreTrainedModel,
```

### Step 2 — Add pipeline class (after line 2779)

Insert the new class between `DocumentQuestionAnsweringPipeline` (ends line 2779) and the `TextToAudioPipeline` block (starts line 2782).

The class follows the exact pattern of `ImageToTextPipeline` and `DocumentQuestionAnsweringPipeline`:

```js
/**
 * @typedef {Object} ImageTextToTextSingle
 * @property {string} generated_text The generated text.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Generate text given an image and a text prompt.
 * @param {ImageInput} image The image to use as context.
 * @param {string} text A text prompt describing what to do with the image.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput>} An object containing the generated text.
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image Text To Text pipeline using any `AutoModelForImageTextToText`. This pipeline generates
 * text given an image and a text prompt.
 *
 * **Example:** Generate text from an image with `onnx-community/Florence-2-base-ft`.
 * ```javascript
 * const pipeline = await pipeline('image-text-to-text', 'onnx-community/Florence-2-base-ft');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipeline(url, 'Describe this image in detail');
 * // [{ generated_text: '...' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(image, text, generate_kwargs = {}) {

        // NOTE: For now, we only support a batch size of 1

        // Preprocess image
        const preparedImage = (await prepareImages(image))[0];
        const { pixel_values } = await this.processor(preparedImage);

        // Run tokenization
